function somar(a, b) {
  return a + b;
}

const resultado = somar(2, 3);

if (resultado !== 5) {
  throw new Error("Esperava 5, mas recebeu " + resultado);
}

function aplicarDesconto(preco, percentual) {
  if (percentual < 0 || percentual > 100) {
    throw new Error("Percentual de desconto deve estar entre 0 e 100.");
  }

  return preco - (preco * percentual) / 100;
}

function buscarUsuario() {
  return Promise.resolve({ id: 1, nome: "Ana" });
}

async function testarUsuario() {
  const usuario = await buscarUsuario();

  if (usuario.nome !== "Ana") {
    throw new Error("Esperava nome Ana.");
  }
}
